import * as express from 'express';
import * as jwt from 'jsonwebtoken';

const app = express();
app.use(jwtDecodeMiddleware);

function jwtDecodeMiddleware(req: express.Request, res: express.Response, next: express.NextFunction) {
    const authHeader = req.headers['authorization'];
    if (authHeader && typeof authHeader === 'string') {
        const token = authHeader.split('Bearer ')[1];
        try {
            const decodedToken = jwt.decode(token, { json: true });
            if (decodedToken) {
                req['user'] = decodedToken; // Attach user info to request object for further use
            } else {
                res.status(401).send('Invalid token');
            }
        } catch (err) {
            console.error("Error while decoding the JWT", err);
            res.status(500).send('Internal server error');
        }
    } else if (!authHeader) {
        // No header, so not authenticated
        res.status(401).send('No token provided');
    }
    next();
}

